module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

    reg previous_a;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            previous_a <= 1'b0;
            rise <= 1'b0;
            down <= 1'b0;
        end else begin
            previous_a <= a;
            rise <= (previous_a == 1'b0 && a == 1'b1) ? 1'b1 : 1'b0;
            down <= (previous_a == 1'b1 && a == 1'b0) ? 1'b1 : 1'b0;
        end
    end

endmodule
